<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Bot Maze — 24 Pathfinders</title>
<style>
  :root {
    --bg: #0d1117;
    --panel: #161b22;
    --accent: #58a6ff;
    --wall: #8b949e;
    --text: #e6edf3;
  }
  * { box-sizing: border-box; }
  body {
    margin: 0;
    min-height: 100vh;
    background: radial-gradient(ellipse at top, #1a2233 0%, var(--bg) 60%);
    color: var(--text);
    font-family: "Segoe UI", system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 24px;
  }
  h1 {
    font-size: 22px;
    font-weight: 600;
    letter-spacing: 1px;
    margin: 0 0 16px;
    color: var(--accent);
  }
  #hud {
    display: flex;
    gap: 14px;
    align-items: center;
    background: var(--panel);
    border: 1px solid #30363d;
    border-radius: 12px;
    padding: 10px 18px;
    margin-bottom: 16px;
    box-shadow: 0 4px 18px rgba(0,0,0,0.4);
  }
  .stat {
    display: flex;
    flex-direction: column;
